/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `trg_distributor_inventory_movement_log` AFTER UPDATE ON `distributor_inventory` FOR EACH ROW BEGIN
    IF OLD.quantity != NEW.quantity THEN
        INSERT INTO `inventory_movements` (
            `inventory_type`,
            `inventory_id`,
            `movement_type`,
            `quantity_before`,
            `quantity_change`,
            `quantity_after`,
            `reason`,
            `movement_date`
        ) VALUES (
            'DISTRIBUTOR',
            NEW.id,
            CASE
                WHEN NEW.quantity > OLD.quantity THEN 'RECEIVE'
                WHEN NEW.quantity < OLD.quantity THEN 'SHIP_OUT'
                ELSE 'ADJUSTMENT'
            END,
            OLD.quantity,
            NEW.quantity - OLD.quantity,
            NEW.quantity,
            'Auto-logged by trigger',
            NOW()
        );
    END IF;
END */;;
DELIMITER ;
